payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建仿生传感基础，实现0.1mm级空间分辨率。"
    },
    {
      "date": "第3月",
      "title": "算法开发与优化",
      "description": "开发分层CNN-LSTM手势识别模型，结合自适应滑动窗口与噪声抑制模块，实现实测准确率>98.2%的毫秒级实时推理能力。"
    },
    {
      "date": "第4月",
      "title": "多模态系统集成",
      "description": "集成视觉-触觉-听觉统一时空对齐协议，嵌入微型电磁致动器与温控反馈单元，构建感知-意图-反馈闭环交互系统。"
    },
    {
      "date": "第5–6月",
      "title": "场景验证与迭代",
      "description": "依托H-Box全息舱、李未可眼镜等平台，在工业远程操控与虚拟实训场景开展压力测试，优化用户体验并形成标准接口。"
    }
  ]
}

